// Process Apollo API results and format leads
const results = $input.all();
const processedLeads = [];

try {
  // Get the raw data from Apollo API
  const apiResponse = results[0]?.json;

  // Check if we have valid response data
  if (!apiResponse || !apiResponse.people) {
    return [{
      json: {
        success: false,
        message: 'No results found from Apollo API',
        query: results[0]?.json?.searchQuery || 'unknown',
        timestamp: new Date().toISOString()
      }
    }];
  }

  // Process each person/lead from the results
  const people = apiResponse.people || [];

  for (const person of people) {
    const lead = {
      // Personal Information
      id: person.id || null,
      fullName: person.name || 'N/A',
      firstName: person.first_name || null,
      lastName: person.last_name || null,
      title: person.title || 'N/A',
      seniority: person.seniority || null,

      // Contact Information
      email: person.email || null,
      emailStatus: person.email_status || 'unknown',
      phone: person.phone_number || null,
      linkedinUrl: person.linkedin_url || null,

      // Company Information
      companyName: person.organization?.name || 'N/A',
      companyDomain: person.organization?.primary_domain || null,
      companyIndustry: person.organization?.industry || null,
      companySize: person.organization?.estimated_num_employees || null,
      companyLocation: {
        city: person.organization?.city || null,
        state: person.organization?.state || null,
        country: person.organization?.country || null,
        fullAddress: person.organization?.street_address || null
      },
      companyPhone: person.organization?.phone || null,
      companyLinkedIn: person.organization?.linkedin_url || null,
      companyFacebook: person.organization?.facebook_url || null,
      companyTwitter: person.organization?.twitter_url || null,

      // Additional Metadata
      departments: person.departments || [],
      keywords: person.organization?.keywords || [],
      technologies: person.organization?.technologies || [],

      // Scoring and Quality
      emailConfidence: person.email_confidence || 0,
      phoneNumberStatus: person.phone_number_status || null,

      // Timestamps
      lastUpdated: person.updated_at || null,
      addedToList: new Date().toISOString()
    };

    processedLeads.push(lead);
  }

  // Return formatted results
  return [{
    json: {
      success: true,
      message: `Successfully retrieved ${processedLeads.length} leads`,
      query: results[0]?.json?.searchQuery || 'unknown',
      location: results[0]?.json?.location || 'unknown',
      totalLeads: processedLeads.length,
      leads: processedLeads,
      timestamp: new Date().toISOString(),
      apiCredits: apiResponse.credits_used || null
    }
  }];

} catch (error) {
  return [{
    json: {
      success: false,
      message: `Error processing results: ${error.message}`,
      query: results[0]?.json?.searchQuery || 'unknown',
      timestamp: new Date().toISOString()
    }
  }];
}

// Format the final response with summary statistics
const results = $input.all();
const leads = results[0]?.json?.qualifiedLeads || [];

// Calculate statistics
const stats = {
  totalQualifiedLeads: leads.length,
  byQuality: {
    high: leads.filter(l => l.leadQuality === 'High').length,
    medium: leads.filter(l => l.leadQuality === 'Medium').length,
    low: leads.filter(l => l.leadQuality === 'Low').length
  },
  byContactType: {
    withEmail: leads.filter(l => l.email !== null).length,
    withPhone: leads.filter(l => l.phone !== null).length,
    withLinkedIn: leads.filter(l => l.linkedinUrl !== null).length
  },
  averageLeadScore: leads.length > 0 
    ? Math.round(leads.reduce((sum, l) => sum + (l.leadScore || 0), 0) / leads.length)
    : 0
};

// Group leads by company
const companiesMap = {};
leads.forEach(lead => {
  const companyName = lead.companyName || 'Unknown';
  if (!companiesMap[companyName]) {
    companiesMap[companyName] = {
      companyName: companyName,
      domain: lead.companyDomain,
      location: lead.companyLocation,
      industry: lead.companyIndustry,
      contacts: []
    };
  }
  companiesMap[companyName].contacts.push({
    name: lead.fullName,
    title: lead.title,
    email: lead.email,
    phone: lead.phone,
    linkedIn: lead.linkedinUrl,
    leadScore: lead.leadScore
  });
});

const companiesList = Object.values(companiesMap)
  .sort((a, b) => b.contacts.length - a.contacts.length);

return [{
  json: {
    success: true,
    summary: {
      message: `Successfully processed lead generation request`,
      timestamp: new Date().toISOString(),
      statistics: stats,
      topCompanies: companiesList.slice(0, 5).map(c => ({
        name: c.companyName,
        contactCount: c.contacts.length,
        domain: c.domain
      }))
    },
    companies: companiesList,
    allLeads: leads,
    exportReady: {
      csv: leads.map(l => ({
        'Full Name': l.fullName,
        'Title': l.title,
        'Company': l.companyName,
        'Email': l.email || '',
        'Phone': l.phone || '',
        'LinkedIn': l.linkedinUrl || '',
        'Lead Score': l.leadScore,
        'Lead Quality': l.leadQuality
      }))
    }
  }
}];
